final:
module top_module (
	input clk,
	input sreset,
	input bin,
	output gray);reg prev_bin;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (sreset)
		prev_bin <= 0;
	else
		prev_bin <= bin;
end

assign gray = bin ^ prev_bin;

endmodule
